/**
 * One-off: revise existing auto-generated articles to match the new
 * 1-source-paraphrase spec.
 *
 * For each `isAutoGenerated=true, status=DRAFT` article:
 *   1. Resolve source — use existing sourceArticleId; if missing, find one
 *      whose title best matches the auto-article's keyword (extracted from
 *      title's strongest noun phrase).
 *   2. If no source found — log + skip.
 *   3. Save current content as a Revision (so editorial work isn't lost).
 *   4. Call DeepSeek with the same paraphrase prompt as the cron.
 *   5. Update article: title (if AI gave a better one), excerpt, content,
 *      featuredImage (from source), categoryId (from source),
 *      sourceArticleId (set if was missing).
 *
 * Usage on VPS:
 *   cd /var/www/kartawarta && node scripts/revise-auto-articles.mjs
 *
 * Idempotent: re-running will paraphrase again from source. Skip-protected
 * by status=DRAFT so editor-touched articles (IN_REVIEW / APPROVED /
 * PUBLISHED) are never overwritten.
 */
import { PrismaClient } from "@prisma/client";

const prisma = new PrismaClient();

function stripHtml(html) {
  return html
    .replace(/<[^>]+>/g, " ")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/\s+/g, " ")
    .trim();
}

function stripCodeFence(raw) {
  const trimmed = raw.trim();
  const fenced = trimmed.match(/^```(?:json)?\s*\n?([\s\S]*?)\n?```$/);
  if (fenced) return fenced[1].trim();
  return trimmed;
}

function safeParseJson(raw) {
  try {
    const cleaned = stripCodeFence(raw);
    const parsed = JSON.parse(cleaned);
    if (
      parsed &&
      typeof parsed === "object" &&
      typeof parsed.title === "string" &&
      typeof parsed.content === "string"
    ) {
      return {
        title: parsed.title.trim(),
        excerpt: typeof parsed.excerpt === "string" ? parsed.excerpt.trim() : "",
        content: parsed.content.trim(),
      };
    }
  } catch {
    // fall through
  }
  return null;
}

async function getDeepSeekKey() {
  const setting = await prisma.systemSetting.findUnique({
    where: { key: "deepseek_api_key" },
  });
  if (!setting?.value) {
    throw new Error("deepseek_api_key not configured in SystemSetting");
  }
  return setting.value;
}

async function callDeepSeek(apiKey, userPrompt) {
  const res = await fetch("https://api.deepseek.com/v1/chat/completions", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify({
      model: "deepseek-chat",
      messages: [
        {
          role: "system",
          content:
            "Kamu adalah asisten AI untuk media berita hukum Indonesia. Output harus JSON valid, tidak boleh ada teks lain di luar JSON.",
        },
        { role: "user", content: userPrompt },
      ],
      max_tokens: 2000,
      temperature: 0.7,
    }),
  });
  if (!res.ok) {
    throw new Error(`DeepSeek HTTP ${res.status}: ${await res.text()}`);
  }
  const json = await res.json();
  return {
    text: json.choices?.[0]?.message?.content?.trim() || "",
    tokens: json.usage?.total_tokens || 0,
  };
}

function buildPrompt(source, keyword) {
  const sourceDate = source.publishedAt
    ? new Date(source.publishedAt).toLocaleDateString("id-ID", {
        day: "numeric",
        month: "long",
        year: "numeric",
      })
    : "";
  const plain = stripHtml(source.content).slice(0, 4500);

  return `Tugas: tulis ulang (PARAFRASA) artikel berita berikut dalam Bahasa Indonesia jurnalistik. Bukan tulis baru, bukan sintesis — paraphrase artikel ini.

ARTIKEL SUMBER:
JUDUL: ${source.title}
KATEGORI: ${source.category?.name ?? "Umum"}
TANGGAL: ${sourceDate}
${source.excerpt ? `RINGKASAN: ${source.excerpt}\n` : ""}ISI:
${plain}

ATURAN PARAFRASA (WAJIB):
1. Pertahankan SEMUA fakta dari sumber — nama, jabatan, angka, tanggal, lokasi, kutipan langsung jangan diubah.
2. Reword setiap kalimat dengan struktur kata baru. Jangan menyalin kalimat persis.
3. Jangan menambah klaim baru, prediksi, atau fakta yang tidak ada di sumber.
4. Jangan menghapus poin penting. Pertahankan urutan kronologis / argumentasi sumber.
5. Panjang artikel paraphrase: ~80–110% panjang sumber. Body 400–800 kata, sesuai sumber.
6. Gaya bahasa: lead 5W+1H di paragraf pertama, paragraf pendek 2–4 kalimat, sertakan minimal 1 sub-heading <h2> kalau sumber punya struktur sectioned.
7. Judul baru: ringkasan inti, 50–80 karakter, BEDA dari judul sumber tapi tetap akurat.
8. Excerpt: 150–200 karakter, fakta paling kuat dari paragraf pertama.

Keyword fokus: "${keyword}"

Format output WAJIB JSON valid (tanpa teks lain, tanpa code-fence):
{
  "title": "judul paraphrase 50-80 karakter",
  "excerpt": "ringkasan 150-200 karakter",
  "content": "body HTML dengan <p>, <h2>, <blockquote> kalau sumber punya kutipan, <ul> kalau ada list"
}`;
}

async function findSourceByKeyword(keyword) {
  const baseWhere = { status: "PUBLISHED", isAutoGenerated: false };
  const queries = [
    { ...baseWhere, title: { contains: keyword, mode: "insensitive" }, featuredImage: { not: null } },
    { ...baseWhere, title: { contains: keyword, mode: "insensitive" } },
    { ...baseWhere, excerpt: { contains: keyword, mode: "insensitive" }, featuredImage: { not: null } },
    { ...baseWhere, excerpt: { contains: keyword, mode: "insensitive" } },
    { ...baseWhere, content: { contains: keyword, mode: "insensitive" }, featuredImage: { not: null } },
    { ...baseWhere, content: { contains: keyword, mode: "insensitive" } },
  ];
  for (const where of queries) {
    const a = await prisma.article.findFirst({
      where,
      orderBy: [{ publishedAt: "desc" }, { viewCount: "desc" }],
      select: {
        id: true,
        title: true,
        excerpt: true,
        content: true,
        featuredImage: true,
        publishedAt: true,
        categoryId: true,
        category: { select: { name: true } },
      },
    });
    if (a) return a;
  }
  return null;
}

/** Extract a probable keyword from the auto-article's title. */
function deriveKeyword(title) {
  // Try active TargetKeyword first that appears in title
  return title; // fallback to full title; findSourceByKeyword does ILIKE so partial OK
}

async function main() {
  const apiKey = await getDeepSeekKey();

  const articles = await prisma.article.findMany({
    where: { isAutoGenerated: true, status: "DRAFT" },
    select: {
      id: true,
      title: true,
      slug: true,
      content: true,
      excerpt: true,
      featuredImage: true,
      sourceArticleId: true,
      categoryId: true,
    },
    orderBy: { createdAt: "asc" },
  });

  console.log(`Found ${articles.length} auto-articles (DRAFT) to revise.\n`);

  const targetKeywords = await prisma.targetKeyword.findMany({
    where: { isActive: true },
    select: { keyword: true },
  });
  const kwList = targetKeywords.map((k) => k.keyword);

  let revised = 0;
  let skipped = 0;
  let failed = 0;

  for (const a of articles) {
    console.log(`\n→ ${a.slug}`);

    // Resolve source
    let source = null;
    if (a.sourceArticleId) {
      source = await prisma.article.findUnique({
        where: { id: a.sourceArticleId },
        select: {
          id: true,
          title: true,
          excerpt: true,
          content: true,
          featuredImage: true,
          publishedAt: true,
          categoryId: true,
          category: { select: { name: true } },
        },
      });
    }
    if (!source) {
      // Try to find by keyword match. Pick the keyword most present in title.
      const lowerTitle = a.title.toLowerCase();
      const matchedKw = kwList.find((kw) => lowerTitle.includes(kw.toLowerCase()));
      const probe = matchedKw || deriveKeyword(a.title);
      source = await findSourceByKeyword(probe);
      if (source) {
        console.log(`  found source by keyword "${probe}": ${source.title.slice(0, 60)}…`);
      }
    } else {
      console.log(`  source: ${source.title.slice(0, 60)}…`);
    }

    if (!source) {
      console.log("  ⚠ no source — skipping");
      skipped++;
      continue;
    }

    // Pick a focus keyword for the prompt (any matched TargetKeyword, else article title)
    const lowerSourceTitle = source.title.toLowerCase();
    const promptKw =
      kwList.find((kw) => lowerSourceTitle.includes(kw.toLowerCase())) ||
      kwList[0] ||
      a.title;

    // Save current content as Revision (so editorial in-progress work isn't lost)
    try {
      await prisma.revision.create({
        data: {
          articleId: a.id,
          title: a.title,
          content: a.content,
          changedBy: "system:revise-auto-articles",
        },
      });
    } catch (e) {
      console.warn(`  ⚠ revision save failed: ${e.message}`);
    }

    // Call AI
    let parsed = null;
    try {
      const ai = await callDeepSeek(apiKey, buildPrompt(source, promptKw));
      parsed = safeParseJson(ai.text);
      console.log(`  AI tokens=${ai.tokens}, parsed=${parsed ? "ok" : "null"}`);
    } catch (e) {
      console.error(`  ✗ AI failed: ${e.message}`);
      failed++;
      continue;
    }

    if (!parsed) {
      console.warn("  ⚠ AI output not valid JSON, skipping update");
      failed++;
      continue;
    }

    // Update article
    try {
      await prisma.article.update({
        where: { id: a.id },
        data: {
          title: parsed.title.slice(0, 250),
          excerpt: (parsed.excerpt || "").slice(0, 500) || a.excerpt,
          content: parsed.content,
          featuredImage: source.featuredImage ?? a.featuredImage,
          categoryId: source.categoryId,
          sourceArticleId: source.id,
        },
      });
      console.log(`  ✓ revised`);
      revised++;
    } catch (e) {
      console.error(`  ✗ update failed: ${e.message}`);
      failed++;
    }
  }

  console.log(`\n──────────`);
  console.log(`Revised: ${revised}`);
  console.log(`Skipped: ${skipped}`);
  console.log(`Failed:  ${failed}`);
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(() => prisma.$disconnect());
